import { useCallback, useRef } from 'react';

import { LegendItem } from '../types/legend.js';
import { indexShouldBeIncludedInShiftClickedList } from '../utils/index-should-be-included-in-shift-clicked-list.js';

/**
 * Hook for selecting items in a different behavior depending on what keys are pressed during the click event.
 * Modifier keys that right now add behavior:
 *
 * - Shift key: it will select from last non-shift-click up to the new shift-click.
 * - Ctrl / Cmd key: it will add or remove selection without altering the other selections. It will
 * update the `last non-shift click` memory that's relevant for following shift clicks.
 * - Non modified click: it will simply select the clicked item. It will also modify the
 * `last non-shift click` memory relevant for future shift-clicks. If only one item is selected, and
 * it is clicked in this way, all items will be re-selected.
 *
 * @param allItems - the complete list of items to be considered
 * @returns selectItem function that should smart-select with MouseEvent modifiers
 */
export function useKeyboardSelectionShortcuts(
  allItems: LegendItem[],
): (
  item: LegendItem,
  hiddenItems: Set<string>,
  event: MouseEvent,
) => LegendItem[] {
  const pivot = useRef<number>(undefined);
  const lastIndexClicked = useRef<number>(undefined);

  const newClickIndex = useCallback(
    (item: LegendItem) => allItems.findIndex((it) => it.id === item.id),
    [allItems],
  );

  const smartSelectionWithShift = (
    item: LegendItem,
    hiddenItems: Set<string>,
  ): LegendItem[] => {
    const currentPivot = pivot.current;
    if (currentPivot === undefined || lastIndexClicked.current === undefined) {
      return simpleSelection(item, hiddenItems);
    }

    const newClick = newClickIndex(item);
    const previousLastClick = lastIndexClicked.current;
    lastIndexClicked.current = newClick;

    return allItems.filter((it, index) =>
      indexShouldBeIncludedInShiftClickedList(
        index,
        newClick,
        currentPivot,
        previousLastClick,
        !hiddenItems.has(it.id),
      ),
    );
  };

  const smartSelectionWithCtrl = (
    item: LegendItem,
    hiddenItems: Set<string>,
  ): LegendItem[] => {
    const newClick = newClickIndex(item);

    pivot.current = newClick;
    lastIndexClicked.current = newClick;

    const visibleItems = allItems.filter((it) => !hiddenItems.has(it.id));

    // if the item is hidden, add it as visible
    if (hiddenItems.has(item.id)) {
      return [...visibleItems, item];
    }

    // if the item is the only one visible, set it as hidden and the rest as visible
    if (visibleItems.length === 1) {
      return allItems.filter((it) => it.id !== item.id);
    }

    // set item to hidden
    return visibleItems.filter((it) => it.id !== item.id);
  };

  const simpleSelection = (
    item: LegendItem,
    hiddenItems: Set<string>,
  ): LegendItem[] => {
    const currentSelectedSize = allItems.length - hiddenItems.size;
    const newClick = newClickIndex(item);

    pivot.current = newClick;
    lastIndexClicked.current = newClick;

    // clicked item is the only selected item
    if (!hiddenItems.has(item.id) && currentSelectedSize === 1) {
      return allItems;
    }

    return [item];
  };

  const selectItem = (
    item: LegendItem,
    hiddenItems: Set<string>,
    event: MouseEvent,
  ): LegendItem[] => {
    const { shiftKey, ctrlKey, metaKey } = event;

    // shift key overrides control / cmd key press
    if (shiftKey) {
      return smartSelectionWithShift(item, hiddenItems);
    }

    if (ctrlKey || metaKey) {
      return smartSelectionWithCtrl(item, hiddenItems);
    }

    return simpleSelection(item, hiddenItems);
  };

  return selectItem;
}
